#include <bits/stdc++.h>
using namespace std;
#define int long long
const int maxn = 105;
int g[maxn],dp[maxn][maxn][maxn],num[1024];
vector<int> sta;
int cal(int x) {
	int res=0;
	while(x) {
		if(x&1) {
			res++;
		}
		x>>=1;
	}
	return res;
}
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	int n,m;
	cin>>n>>m;
	for(int i=1; i<=n; i++) {
		for(int j=0; j<m; j++) {
			char c;
			cin>>c;
			if(c=='H') {
				g[i]|=(1<<j);
			}
		}
	}
	for(int i=0; i<(1<<m); i++) {
		if(!(i&(i<<1))&&!(i&(i<<2))) {
			sta.push_back(i);
			num[i]=cal(i);
		}
	}
	int cnt=sta.size();
	for(int i=1; i<=n; i++) {
		for(int u=0; u<cnt; u++) {
			if(sta[u]&g[i])continue;
			for(int k=0; k<cnt; k++) {
				if(sta[k]&g[i-1]) {
					continue;
				}
				if(sta[u]&sta[k]) {
					continue;
				}
				for(int l=0; l<cnt; l++) {
					if(sta[l]&g[i-2])continue;
					if((sta[u]&sta[l])||(sta[k]&sta[l]))continue;
					dp[i][u][k]=max(dp[i][u][k],dp[i-1][k][l]+num[sta[u]]);
				}
			}
		}
	}
	int ans=0;
	for(int j=0; j<cnt; j++) {
		for(int k=0; k<cnt; k++) {
			ans=max(ans,dp[n][j][k]);
		}
	}
	cout<<ans;
	return 0;
}
